1	/**
2	 * PopDAM Cloud Worker — entry point.
3	 *
4	 * Runs a continuous polling loop:
5	 *   1. Check admin_config.BULK_OPERATIONS for running/queued ops
6	 *   2. Dispatch to the appropriate handler
7	 *   3. Process batches until done or user stops
8	 *   4. Sleep WORKER_POLL_INTERVAL_MS, repeat
9	 *
10	 * Handles graceful shutdown on SIGTERM/SIGINT.
11	 */
12	
13	import { config } from "./config.js";
14	import { logger } from "./logger.js";
15	import { tick } from "./operation-loop.js";
16	
17	const sleep = (ms: number) => new Promise((r) => setTimeout(r, ms));
18	
19	let running = true;
20	
21	function shutdown(signal: string) {
22	  logger.info("worker: shutdown signal received", { signal });
23	  running = false;
24	}
25	
26	process.on("SIGTERM", () => shutdown("SIGTERM"));
27	process.on("SIGINT", () => shutdown("SIGINT"));
28	
29	async function main() {
30	  logger.info("worker: starting", {
31	    supabase_url: config.supabaseUrl,
32	    poll_interval_ms: config.pollIntervalMs,
33	    ai_batch_size: config.aiBatchSize,
34	    ai_batch_concurrency: config.aiBatchConcurrency,
35	  });
36	
37	  // Verify Supabase connection
38	  const { db } = await import("./supabase.js");
39	  const { error: pingErr } = await db().from("admin_config").select("key").limit(1);
40	  if (pingErr) {
41	    logger.error("worker: Supabase connection failed", { error: pingErr.message });
42	    process.exit(1);
43	  }
44	  logger.info("worker: connected to Supabase — polling loop started");
45	
46	  while (running) {
47	    try {
48	      await tick();
49	    } catch (e) {
50	      logger.error("worker: unhandled error in tick", {
51	        error: e instanceof Error ? e.message : String(e),
52	        stack: e instanceof Error ? e.stack : undefined,
53	      });
54	    }
55	    await sleep(config.pollIntervalMs);
56	  }
57	
58	  logger.info("worker: shutdown complete");
59	}
60	
61	main().catch((e) => {
62	  logger.error("worker: fatal error", { error: e instanceof Error ? e.message : String(e) });
63	  process.exit(1);
64	});
65

1	/**
2	 * Operation loop — polls admin_config.BULK_OPERATIONS, dispatches to handlers,
3	 * persists state after each batch.
4	 *
5	 * Ports orchestration logic from supabase/functions/bulk-job-runner/index.ts.
6	 *
7	 * Key differences from bulk-job-runner:
8	 *   - No 45s time budget — processes until done or stopped
9	 *   - No AUTO_RESUME_MAX_ATTEMPTS ceiling — worker handles ops directly
10	 *   - No HTTP round-trips to admin-api or ai-tag edge functions
11	 *   - Checks for user interruption every 10 batches (same threshold)
12	 *   - Stale lock detection: same 10-minute threshold
13	 */
14	
15	import { db } from "./supabase.js";
16	import { logger } from "./logger.js";
17	import type { BatchResult, OpState } from "./types.js";
18	import { handleBulkAiTag } from "./handlers/ai-tagging.js";
19	import { handleCleanupMegaGroupTags, handleRebuildStyleGroups, handleReconcileStyleGroupStats } from "./handlers/style-groups.js";
20	import { handleRelinkOrphanedAssets } from "./handlers/relink-orphaned.js";
21	import { handlePropagateGroupTags } from "./handlers/tag-propagation.js";
22	import { handleApplyErpEnrichment, handleClassifyErpCategories } from "./handlers/erp.js";
23	import { maybeMirrorSeaDrive } from "./handlers/seadrive-mirror.js";
24	
25	const CONFIG_KEY = "BULK_OPERATIONS";
26	const STALE_RUN_MINUTES = 10;
27	const INTERRUPT_CHECK_EVERY = 10;
28	/** Yield after this many batches so the round-robin can serve other operations.
29	 *  Under the old 45s edge function, 5 was the max that fit safely. The persistent
30	 *  worker has no timeout, so 50 keeps ops running hot while still yielding often
31	 *  enough to check for user interruptions and serve other lanes. */
32	const MAX_BATCHES_PER_TICK = 50;
33	
34	// Lane isolation — operations in the same lane are mutually exclusive
35	const OP_LANES: Record<string, string> = {
36	  "ai-tag-untagged": "ai-tagging",
37	  "ai-tag-all": "ai-tagging",
38	  "ai-tag-groups": "ai-tagging",
39	  "rebuild-style-groups": "style-groups",
40	  "reconcile-style-group-stats": "style-groups",
41	  "reprocess-metadata": "metadata",
42	  "backfill-sku-names": "metadata",
43	  "erp-enrichment": "erp",
44	  "erp-classify": "erp",
45	  "propagate-group-tags": "style-groups",
46	  "cleanup-mega-group-tags": "style-groups",
47	  "relink-orphaned-assets": "style-groups",
48	};
49	
50	// Cross-lane conflicts — operations in DIFFERENT lanes that still cannot run simultaneously.
51	// Root cause: speculative-insert index locks on asset_tags B-tree index when both ai-tag and
52	// propagate-group-tags INSERT the same (asset_id, tag) pair. SKIP LOCKED only fixes UPDATE
53	// locks, not INSERT index locks. Must be kept in sync with:
54	//   supabase/functions/_shared/operation-constants.ts  (backend enforcement)
55	//   src/components/settings/diagnostics/types.ts       (UI pre-flight check)
56	const OP_CONFLICTS: Readonly<Record<string, readonly string[]>> = {
57	  "ai-tag-untagged":      ["rebuild-style-groups", "reprocess-metadata", "propagate-group-tags"],
58	  "ai-tag-all":           ["rebuild-style-groups", "reprocess-metadata", "propagate-group-tags"],
59	  "ai-tag-groups":        ["rebuild-style-groups", "reprocess-metadata", "propagate-group-tags"],
60	  "propagate-group-tags": ["ai-tag-untagged", "ai-tag-all", "ai-tag-groups"],
61	  "rebuild-style-groups": ["ai-tag-untagged", "ai-tag-all", "ai-tag-groups"],
62	  "reprocess-metadata":   ["ai-tag-untagged", "ai-tag-all", "ai-tag-groups", "erp-enrichment"],
63	  "backfill-sku-names":   ["erp-enrichment"],
64	  "erp-enrichment":       ["reprocess-metadata", "backfill-sku-names"],
65	};
66	
67	function getLane(opKey: string): string {
68	  if (opKey.startsWith("ai-tag-single-")) return "ai-tagging";
69	  return OP_LANES[opKey] ?? opKey;
70	}
71	
72	function detectStaleRun(op: OpState): boolean {
73	  if (op.status !== "running") return false;
74	  if (!op.updated_at) return false;
75	  const ageMs = Date.now() - new Date(op.updated_at).getTime();
76	  return ageMs > STALE_RUN_MINUTES * 60 * 1000;
77	}
78	
79	// ── Progress accumulator — mirrors buildProgress() in bulk-job-runner ────────
80	
81	function mergeProgress(opKey: string, prev: Record<string, unknown>, batch: BatchResult): Record<string, unknown> {
82	  // Normalize dynamic keys for matching
83	  const normalizedKey = opKey.startsWith("ai-tag-single-") ? "ai-tag-all" : opKey;
84	  switch (normalizedKey) {
85	    case "ai-tag-untagged":
86	    case "ai-tag-all":
87	    case "ai-tag-groups": {
88	      const prevFail = Array.isArray(prev.failure_samples) ? prev.failure_samples as unknown[] : [];
89	      const batchFail = Array.isArray(batch.failure_samples) ? batch.failure_samples as unknown[] : [];
90	      const prevSkip = Array.isArray(prev.skip_samples) ? prev.skip_samples as unknown[] : [];
91	      const batchSkip = Array.isArray(batch.skip_samples) ? batch.skip_samples as unknown[] : [];
92	      return {
93	        tagged: ((prev.tagged as number) || 0) + ((batch.tagged as number) || 0),
94	        skipped: ((prev.skipped as number) || 0) + ((batch.skipped as number) || 0),
95	        failed: ((prev.failed as number) || 0) + ((batch.failed as number) || 0),
96	        // Prefer previously-set total; fall back to batch-supplied count (set by handler when total is unknown)
97	        total: (prev.total as number) || (batch.total_count as number) || 0,
98	        failure_samples: [...prevFail, ...batchFail].slice(-200),
99	        skip_samples: [...prevSkip, ...batchSkip].slice(-200),
100	      };
101	    }
102	    case "rebuild-style-groups":
103	      return {
104	        groups: ((prev.groups as number) || 0) + ((batch.groups_created as number) || 0),
105	        assigned: ((prev.assigned as number) || 0) + ((batch.assets_assigned as number) || 0),
106	        cleared: ((prev.cleared as number) || 0) + ((batch.cleared_assets as number) || 0),
107	        groups_deleted: ((prev.groups_deleted as number) || 0) + ((batch.groups_deleted as number) || 0),
108	        total_groups_before_delete: Math.max((prev.total_groups_before_delete as number) || 0, (batch.total_groups_before_delete as number) || 0),
109	        total_processed: Math.max((prev.total_processed as number) || 0, (batch.total_processed as number) || 0),
110	        total_assets: Math.max((prev.total_assets as number) || 0, (batch.total_assets as number) || 0),
111	        counts_processed: Math.max((prev.counts_processed as number) || 0, (batch.counts_processed as number) || 0),
112	        primaries_processed: Math.max((prev.primaries_processed as number) || 0, (batch.primaries_processed as number) || 0),
113	        finalize_total_groups: Math.max((prev.finalize_total_groups as number) || 0, (batch.finalize_total_groups as number) || 0),
114	        stage: batch.stage || prev.stage,
115	        substage: batch.sub || batch.substage || prev.substage,
116	      };
117	    case "reconcile-style-group-stats":
118	      return {
119	        counts_processed: Math.max((prev.counts_processed as number) || 0, (batch.counts_processed as number) || 0),
120	        primaries_processed: Math.max((prev.primaries_processed as number) || 0, (batch.primaries_processed as number) || 0),
121	        total_groups: Math.max((prev.total_groups as number) || 0, (batch.total_groups as number) || 0),
122	        stage: batch.sub || prev.stage,
123	      };
124	    case "erp-enrichment":
125	      return {
126	        updated: ((prev.updated as number) || 0) + ((batch.updated as number) || 0),
127	        total: Math.max((prev.total as number) || 0, (batch.total as number) || 0),
128	        assets_updated: ((prev.assets_updated as number) || 0) + ((batch.assets_updated as number) || 0),
129	        groups_updated: ((prev.groups_updated as number) || 0) + ((batch.groups_updated as number) || 0),
130	      };
131	    case "erp-classify":
132	      return {
133	        classified: ((prev.classified as number) || 0) + ((batch.classified as number) || 0),
134	        skipped_unclassifiable: ((prev.skipped_unclassifiable as number) || 0) + ((batch.skipped_unclassifiable as number) || 0),
135	        total: ((prev.total as number) || 0) + ((batch.total as number) || 0),
136	      };
137	    case "propagate-group-tags":
138	      return {
139	        propagated: ((prev.propagated as number) || 0) + ((batch.propagated as number) || 0),
140	        skipped: ((prev.skipped as number) || 0) + ((batch.skipped as number) || 0),
141	        total: prev.total || 0,
142	      };
143	    case "cleanup-mega-group-tags":
144	      return {
145	        groups_processed: ((prev.groups_processed as number) || 0) + ((batch.groups_processed as number) || 0),
146	        tags_deleted: ((prev.tags_deleted as number) || 0) + ((batch.tags_deleted as number) || 0),
147	        characters_deleted: ((prev.characters_deleted as number) || 0) + ((batch.characters_deleted as number) || 0),
148	        metadata_cleared: ((prev.metadata_cleared as number) || 0) + ((batch.metadata_cleared as number) || 0),
149	      };
150	    case "relink-orphaned-assets":
151	      return {
152	        relinked: ((prev.relinked as number) || 0) + ((batch.relinked as number) || 0),
153	        errors: ((prev.errors as number) || 0) + ((batch.errors as number) || 0),
154	      };
155	    default:
156	      return { ...prev, ...batch };
157	  }
158	}
159	
160	// ── Error classifier ─────────────────────────────────────────────────────────
161	
162	/** Map a raw error message to a known reason_code. */
163	function classifyError(msg: string): string {
164	  const m = msg.toLowerCase();
165	  if (m.includes("canceling statement due to statement timeout")) return "statement_timeout";
166	  if (m.includes("bad gateway") || m.includes("502") || m.includes("503") || m.includes("504")) return "gateway_timeout";
167	  if (m.includes("too many connections") || m.includes("connection refused")) return "connection_error";
168	  if (m.includes("rate limit") || m.includes("429")) return "rate_limited";
169	  return "unknown";
170	}
171	
172	// ── Failure kill switch ───────────────────────────────────────────────────────
173	
174	// Tier 1: if the last N failures are all the same error, stop immediately.
175	// Catches systematic breakage (missing column, bad API key) without waiting
176	// for a large sample. Does not require failures to be consecutive — skips
177	// and successes in between don't reset it.
178	const KILL_SAME_ERROR_COUNT = 20;
179	
180	// Tier 2: if the overall failure rate exceeds this threshold once a minimum
181	// number of assets have been processed, stop. Catches high-rate mixed errors
182	// that tier 1 misses (e.g. several different timeout messages).
183	const KILL_RATE_THRESHOLD = 0.80;   // 80% failure rate
184	const KILL_RATE_MIN_SAMPLE = 50;    // need at least this many processed first
185	
186	/**
187	 * Returns a human-readable reason string if the kill switch should fire,
188	 * otherwise null. Two independent tiers — either can trigger.
189	 * Only considers failures that occurred on or after startedAt (current run).
190	 */
191	function detectFailureKillSwitch(progress: Record<string, unknown>, startedAt?: string): string | null {
192	  const allSamples = progress.failure_samples as Array<{ at?: string; error?: string }> | undefined;
193	  const startMs = startedAt ? new Date(startedAt).getTime() : 0;
194	
195	  // Only consider failures from the current run (filter by started_at)
196	  const samples = allSamples?.filter((s) => !s.at || new Date(s.at).getTime() >= startMs);
197	
198	  const failed  = (progress.failed  as number) || 0;
199	  const tagged  = (progress.tagged  as number) || 0;
200	  const skipped = (progress.skipped as number) || 0;
201	  const total   = tagged + skipped + failed;
202	
203	  // Tier 1: last N failures share the same error (non-consecutive — just the last N in the sample list)
204	  if (samples && samples.length >= KILL_SAME_ERROR_COUNT) {
205	    const recent = samples.slice(-KILL_SAME_ERROR_COUNT);
206	    const normalize = (e?: string) => (e ?? "").slice(0, 120).trim();
207	    const first = normalize(recent[0].error);
208	    if (first && recent.every((s) => normalize(s.error) === first)) {
209	      return `Last ${KILL_SAME_ERROR_COUNT} failures share the same error: "${first.slice(0, 200)}"`;
210	    }
211	  }
212	
213	  // Tier 2: overall failure rate too high across a meaningful sample
214	  if (total >= KILL_RATE_MIN_SAMPLE && failed / total >= KILL_RATE_THRESHOLD) {
215	    return `Failure rate ${Math.round((failed / total) * 100)}% (${failed} failed out of ${total} processed)`;
216	  }
217	
218	  return null;
219	}
220	
221	function buildResultMessage(opKey: string, progress: Record<string, unknown>): string {
222	  const normalizedKey = opKey.startsWith("ai-tag-single-") ? "ai-tag-all" : opKey;
223	  switch (normalizedKey) {
224	    case "ai-tag-untagged":
225	    case "ai-tag-all":
226	    case "ai-tag-groups":
227	      return `Tagged ${progress.tagged}. ${progress.skipped || 0} skipped. ${progress.failed || 0} failed.`;
228	    case "rebuild-style-groups":
229	      return `Created ${progress.groups} style groups, assigned ${progress.assigned} assets`;
230	    case "reconcile-style-group-stats":
231	      return `Reconciled counts for ${progress.counts_processed || 0} groups, primaries for ${progress.primaries_processed || 0} groups`;
232	    case "erp-enrichment":
233	      return `Enriched ${progress.assets_updated || 0} assets, ${progress.groups_updated || 0} groups`;
234	    case "erp-classify":
235	      return `AI-classified ${progress.classified || 0} items (${progress.skipped_unclassifiable || 0} unclassifiable)`;
236	    case "propagate-group-tags":
237	      return `Propagated tags across ${progress.propagated || 0} groups (${progress.skipped || 0} skipped)`;
238	    case "cleanup-mega-group-tags":
239	      return `Cleaned ${progress.groups_processed || 0} mega-groups: ${progress.tags_deleted || 0} tags deleted, ${progress.characters_deleted || 0} characters removed, ${progress.metadata_cleared || 0} assets metadata cleared`;
240	    case "relink-orphaned-assets":
241	      return `Relinked ${progress.relinked || 0} orphaned assets${progress.errors ? `, ${progress.errors} errors` : ""}`;
242	    default:
243	      return "Operation completed";
244	  }
245	}
246	
247	// ── Dispatcher ────────────────────────────────────────────────────────────────
248	
249	async function dispatch(opKey: string, opState: OpState): Promise<BatchResult> {
250	  // Handle dynamic single-asset tagging keys (ai-tag-single-{uuid})
251	  if (opKey.startsWith("ai-tag-single-")) {
252	    return handleBulkAiTag(opState, true);
253	  }
254	
255	  switch (opKey) {
256	    case "ai-tag-untagged":
257	      return handleBulkAiTag(opState, false);
258	    case "ai-tag-all":
259	    case "ai-tag-groups":
260	      return handleBulkAiTag(opState, true);
261	    case "rebuild-style-groups":
262	      return handleRebuildStyleGroups(opState);
263	    case "reconcile-style-group-stats":
264	      return handleReconcileStyleGroupStats(opState);
265	    case "propagate-group-tags":
266	      return handlePropagateGroupTags(opState);
267	    case "cleanup-mega-group-tags":
268	      return handleCleanupMegaGroupTags(opState);
269	    case "relink-orphaned-assets":
270	      return handleRelinkOrphanedAssets(opState);
271	    case "erp-enrichment":
272	      return handleApplyErpEnrichment(opState);
273	    case "erp-classify":
274	      return handleClassifyErpCategories(opState);
275	    default:
276	      return { ok: false, done: false, error: `Unknown operation: ${opKey}` };
277	  }
278	}
279	
280	// ── Persist single op state ───────────────────────────────────────────────────
281	
282	/**
283	 * Persist op state. When onlyIfRunning=true, passes p_only_if_status="running"
284	 * so the write is a no-op if the user has stopped the op in the meantime.
285	 * Returns true if the state was successfully written (or if onlyIfRunning=false).
286	 * Returns false if the write was rejected because the op is no longer "running".
287	 */
288	async function persistOpState(opKey: string, opState: OpState, onlyIfRunning = false): Promise<boolean> {
289	  const client = db();
290	  const params: Record<string, unknown> = {
291	    p_op_key: opKey,
292	    p_op_state: opState,
293	  };
294	  if (onlyIfRunning) {
295	    params.p_only_if_status = "running";
296	  }
297	  const { data, error } = await client.rpc("update_bulk_operation", params);
298	  if (error || !data) return true; // on error, don't bail — let the interrupt check handle it
299	  if (!onlyIfRunning) return true;
300	  // Check if our write was applied: the returned state should have status="running"
301	  const allOps = data as Record<string, OpState>;
302	  return allOps[opKey]?.status === "running";
303	}
304	
305	// ── Main tick — called every POLL_INTERVAL_MS ─────────────────────────────────
306	
307	export async function tick(): Promise<void> {
308	  const client = db();
309	
310	  // Best-effort, self-throttled (weekly) — never blocks or breaks the op loop.
311	  await maybeMirrorSeaDrive();
312	
313	  // Load all operations
314	  const { data: configRow, error: configErr } = await client
315	    .from("admin_config")
316	    .select("value")
317	    .eq("key", CONFIG_KEY)
318	    .maybeSingle();
319	
320	  if (configErr) {
321	    logger.error("tick: failed to load BULK_OPERATIONS", { error: configErr.message });
322	    return;
323	  }
324	
325	  const allOps = (configRow?.value as Record<string, OpState>) || {};
326	
327	  // Stale lock detection
328	  const staleUpdates: Record<string, OpState> = {};
329	  for (const [key, op] of Object.entries(allOps)) {
330	    if (detectStaleRun(op)) {
331	      logger.warn("tick: stale lock detected", { opKey: key, last_updated: op.updated_at });
332	      allOps[key] = {
333	        ...op,
334	        status: "interrupted",
335	        interruption_reason_code: "stale_run",
336	        error: `No progress for ${STALE_RUN_MINUTES}+ minutes — marked as stale`,
337	        updated_at: new Date().toISOString(),
338	      };
339	      staleUpdates[key] = allOps[key];
340	    }
341	  }
342	
343	  // Persist stale lock changes
344	  for (const [key, op] of Object.entries(staleUpdates)) {
345	    await persistOpState(key, op);
346	  }
347	
348	  // Auto-resume interrupted ops (e.g. after a deploy killed the previous worker).
349	  // Only resume ops that were NOT stopped by the user and have a valid cursor.
350	  // Cap at AUTO_RESUME_MAX_ATTEMPTS to prevent infinite crash loops.
351	  const AUTO_RESUME_MAX_ATTEMPTS = 10;
352	  const autoResumeUpdates: Record<string, OpState> = {};
353	  for (const [key, op] of Object.entries(allOps)) {
354	    if (
355	      op.status === "interrupted" &&
356	      op.interruption_reason_code !== "user_stop" &&
357	      typeof op.cursor === "number" &&
358	      (op.auto_resume_attempts ?? 0) < AUTO_RESUME_MAX_ATTEMPTS
359	    ) {
360	      const attempts = (op.auto_resume_attempts ?? 0) + 1;
361	      logger.info("tick: auto-resuming interrupted op", { opKey: key, attempts, reason: op.interruption_reason_code });
362	      allOps[key] = {
363	        ...op,
364	        status: "running",
365	        auto_resume_attempts: attempts,
366	        last_auto_resume_at: new Date().toISOString(),
367	        updated_at: new Date().toISOString(),
368	      };
369	      autoResumeUpdates[key] = allOps[key];
370	    }
371	  }
372	  for (const [key, op] of Object.entries(autoResumeUpdates)) {
373	    await persistOpState(key, op);
374	  }
375	
376	  // Promote queued ops into empty lanes
377	  const runningEntries = Object.entries(allOps).filter(([, op]) => op.status === "running");
378	  const activeLanes = new Set(runningEntries.map(([k]) => getLane(k)));
379	
380	  const queuedEntries = Object.entries(allOps)
381	    .filter(([, op]) => op.status === "queued")
382	    .sort((a, b) => {
383	      const posA = a[1].queue_position ?? Number.MAX_SAFE_INTEGER;
384	      const posB = b[1].queue_position ?? Number.MAX_SAFE_INTEGER;
385	      if (posA !== posB) return posA - posB;
386	      return new Date(a[1].updated_at || 0).getTime() - new Date(b[1].updated_at || 0).getTime();
387	    });
388	
389	  const runningKeys = new Set(runningEntries.map(([k]) => k));
390	
391	  for (const [nextOpKey, nextOp] of queuedEntries) {
392	    const lane = getLane(nextOpKey);
393	    if (activeLanes.has(lane)) continue;
394	
395	    // Cross-lane conflict check: skip if any currently-running op conflicts with this one
396	    const crossConflicts = OP_CONFLICTS[nextOpKey] ?? [];
397	    const hasConflict = crossConflicts.some((conflictKey) => runningKeys.has(conflictKey));
398	    if (hasConflict) continue;
399	
400	    logger.info("tick: promoting queued op", { opKey: nextOpKey, lane });
401	    allOps[nextOpKey] = {
402	      ...nextOp,
403	      status: "running",
404	      started_at: new Date().toISOString(),
405	      updated_at: new Date().toISOString(),
406	    };
407	    runningEntries.push([nextOpKey, allOps[nextOpKey]]);
408	    runningKeys.add(nextOpKey);
409	    activeLanes.add(lane);
410	    await persistOpState(nextOpKey, allOps[nextOpKey]);
411	  }
412	
413	  if (runningEntries.length === 0) {
414	    return; // Nothing to do — idle
415	  }
416	
417	  // Round-robin: pick least-recently-updated running op
418	  runningEntries.sort((a, b) => {
419	    const aTime = a[1].updated_at ? new Date(a[1].updated_at).getTime() : 0;
420	    const bTime = b[1].updated_at ? new Date(b[1].updated_at).getTime() : 0;
421	    return aTime - bTime;
422	  });
423	
424	  const [opKey, opState] = runningEntries[0] as [string, OpState];
425	
426	  // Legacy op: no cursor — mark interrupted
427	  if (opState.cursor === undefined) {
428	    await persistOpState(opKey, {
429	      ...opState,
430	      status: "interrupted",
431	      interruption_reason_code: "legacy_format",
432	      updated_at: new Date().toISOString(),
433	    });
434	    logger.warn("tick: legacy op interrupted", { opKey });
435	    return;
436	  }
437	
438	  // Create a mutable copy of opState to avoid mutating the original
439	  let currentState = { ...opState };
440	  if (!currentState.run_id) {
441	    currentState = { ...currentState, run_id: Math.random().toString(36).slice(2) };
442	  }
443	
444	  let cursor = currentState.cursor ?? 0;
445	  let progress = { ...(currentState.progress ?? {}) };
446	  let batchCount = 0;
447	
448	  logger.info("tick: processing op", { opKey, cursor, run_id: opState.run_id });
449	
450	  // Process batches until done or user stops
451	  while (true) {
452	    // Periodic interrupt check (every 10 batches)
453	    if (batchCount > 0 && batchCount % INTERRUPT_CHECK_EVERY === 0) {
454	      const { data: freshConfig } = await client
455	        .from("admin_config")
456	        .select("value")
457	        .eq("key", CONFIG_KEY)
458	        .maybeSingle();
459	      const freshOps = (freshConfig?.value as Record<string, OpState>) || {};
460	      if (freshOps[opKey]?.status !== "running") {
461	        logger.info("tick: op stopped by user", { opKey, batches: batchCount });
462	        return;
463	      }
464	    }
465	
466	    let result: BatchResult;
467	    try {
468	      result = await dispatch(opKey, { ...currentState, cursor, progress });
469	    } catch (e) {
470	      const errMsg = e instanceof Error ? e.message : String(e);
471	      logger.error("tick: dispatch threw", { opKey, error: errMsg });
472	      await persistOpState(opKey, {
473	        ...currentState,
474	        cursor,
475	        progress,
476	        status: "interrupted",
477	        interruption_reason_code: classifyError(errMsg),
478	        error: errMsg,
479	        updated_at: new Date().toISOString(),
480	      });
481	      return;
482	    }
483	
484	    progress = mergeProgress(opKey, progress, result);
485	    batchCount++;
486	
487	    // Kill switch: stop automatically on systematic or high-rate failures.
488	    // Scoped to the current run via started_at so restarting resets the window.
489	    const killReason = detectFailureKillSwitch(progress, currentState.started_at);
490	    if (killReason) {
491	      logger.error("tick: failure kill switch triggered", { opKey, reason: killReason, batchCount });
492	      await persistOpState(opKey, {
493	        ...currentState,
494	        cursor,
495	        progress,
496	        status: "interrupted",
497	        interruption_reason_code: "repeated_failure",
498	        error: `Auto-stopped: ${killReason}`,
499	        updated_at: new Date().toISOString(),
500	      });
501	      return;
502	    }
503	
504	    if (!result.ok) {
505	      const batchErr = result.error ?? "Batch failed";
506	      logger.error("tick: batch failed", { opKey, error: batchErr, batchCount });
507	      await persistOpState(opKey, {
508	        ...currentState,
509	        cursor,
510	        progress,
511	        status: "interrupted",
512	        interruption_reason_code: classifyError(batchErr),
513	        error: batchErr,
514	        updated_at: new Date().toISOString(),
515	      });
516	      return;
517	    }
518	
519	    // Advance cursor
520	    if (result.nextOffset !== undefined && result.nextOffset !== null) {
521	      cursor = result.nextOffset as number | string;
522	    } else if (typeof cursor === "number") {
523	      cursor = cursor + 1;
524	    }
525	
526	    // Save progress after every batch — conditional on status still being "running"
527	    // so a user stop isn't silently overwritten by the worker's next persist.
528	    const stillRunning = await persistOpState(opKey, {
529	      ...currentState,
530	      cursor,
531	      progress,
532	      status: "running",
533	      updated_at: new Date().toISOString(),
534	    }, true);
535	    if (!stillRunning) {
536	      logger.info("tick: op stopped externally — aborting after batch", { opKey, batchCount });
537	      return;
538	    }
539	
540	    if (result.done) {
541	      logger.info("tick: op completed", { opKey, batches: batchCount, progress });
542	      await persistOpState(opKey, {
543	        ...currentState,
544	        cursor,
545	        progress,
546	        status: "completed",
547	        result_message: buildResultMessage(opKey, progress),
548	        updated_at: new Date().toISOString(),
549	      });
550	      return;
551	    }
552	
553	    // Yield after MAX_BATCHES_PER_TICK so other operations get a turn
554	    if (batchCount >= MAX_BATCHES_PER_TICK) {
555	      logger.info("tick: yielding after max batches", { opKey, batches: batchCount, cursor });
556	      return; // State already saved above; main loop re-enters tick()
557	    }
558	  }
559	}
