45	  creds: SpacesCredentials,
46	): Promise<boolean> {
47	  const now = new Date();
48	  const amzDate = now.toISOString().replace(/[:-]/g, "").replace(/\.\d{3}Z$/, "Z");
49	  const dateStamp = amzDate.slice(0, 8);
50	
51	  const host = `${creds.bucket}.${creds.region}.digitaloceanspaces.com`;
52	  const encodedKey = objectKey.split("/").map(encodeURIComponent).join("/");
53	  const url = `https://${host}/${encodedKey}`;
54	
55	  const payloadHash = await sha256Hex("");
56	  const canonicalHeaders = `host:${host}\nx-amz-content-sha256:${payloadHash}\nx-amz-date:${amzDate}\n`;
57	  const signedHeaders = "host;x-amz-content-sha256;x-amz-date";
58	
59	  const canonicalRequest = [
60	    "DELETE",
61	    `/${encodedKey}`,
62	    "",
63	    canonicalHeaders,
64	    signedHeaders,
65	    payloadHash,
66	  ].join("\n");
67	
68	  const credentialScope = `${dateStamp}/${creds.region}/s3/aws4_request`;
69	  const stringToSign = [
70	    "AWS4-HMAC-SHA256",
71	    amzDate,
72	    credentialScope,
73	    await sha256Hex(canonicalRequest),
74	  ].join("\n");
75	
76	  const enc = new TextEncoder();
77	  const kDate = await hmacSha256Bytes(enc.encode(`AWS4${creds.secret}`), dateStamp);
78	  const kRegion = await hmacSha256Bytes(kDate, creds.region);
79	  const kService = await hmacSha256Bytes(kRegion, "s3");
80	  const kSigning = await hmacSha256Bytes(kService, "aws4_request");
81	  const signature = await hmacSha256Hex(kSigning, stringToSign);
82	
83	  const authorization = [
84	    `AWS4-HMAC-SHA256 Credential=${creds.key}/${credentialScope}`,
85	    `SignedHeaders=${signedHeaders}`,
86	    `Signature=${signature}`,
87	  ].join(", ");
88	
89	  const res = await fetch(url, {
90	    method: "DELETE",
91	    headers: {
92	      "host": host,
93	      "x-amz-content-sha256": payloadHash,
94	      "x-amz-date": amzDate,
95	      "authorization": authorization,
96	    },
97	  });
98	
99	  if (res.status === 204 || res.status === 200) return true;
100	  if (res.status === 404) return false;
101	
102	  const body = await res.text();
103	  throw new Error(`DO Spaces DELETE ${objectKey} failed: HTTP ${res.status} — ${body.slice(0, 300)}`);
104	}
