106	/** Delete multiple objects. Returns { deleted, notFound, failed } counts. */
107	export async function deleteSpacesObjects(
108	  keys: string[],
109	  creds: SpacesCredentials,
110	): Promise<{ deleted: number; notFound: number; errors: string[] }> {
111	  let deleted = 0;
112	  let notFound = 0;
113	  const errors: string[] = [];
114	
115	  for (const key of keys) {
116	    try {
117	      const found = await deleteSpacesObject(key, creds);
118	      if (found) deleted++;
119	      else notFound++;
120	    } catch (e) {
121	      errors.push((e as Error).message);
122	    }
123	  }
124	
125	  return { deleted, notFound, errors };
126	}
