128	/** Read SpacesCredentials from admin_config rows (DO_SPACES_KEY, DO_SPACES_SECRET, SPACES_CONFIG). */
129	export function credentialsFromConfig(
130	  configMap: Record<string, unknown>,
131	): SpacesCredentials | null {
132	  const key = configMap.DO_SPACES_KEY as string | null;
133	  const secret = configMap.DO_SPACES_SECRET as string | null;
134	  const spaces = (configMap.SPACES_CONFIG as Record<string, string> | null) || {};
135	
136	  if (!key || !secret) return null;
137	
138	  return {
139	    key,
140	    secret,
141	    bucket: spaces.bucket_name || spaces.bucket || "popdam",
142	    region: spaces.region || "nyc3",
143	  };
144	}
