432	        await client.from("asset_tags").delete().eq("asset_id", assetId).eq("source", "ai");
433	        const tagRows = (tagData.tags as string[]).map((t: string) => ({
434	          asset_id: assetId,
435	          tag: t.trim().toLowerCase(),
436	          source: "ai",
437	        }));
438	        await client.from("asset_tags").upsert(tagRows, { onConflict: "asset_id,tag" });
439	      }
440	
441	      // Write character links
442	      if (Array.isArray(tagData.character_ids) && tagData.character_ids.length > 0) {
443	        const validCharIds = (tagData.character_ids as string[]).filter((cid) => isValidUuid(cid));
444	        if (validCharIds.length > 0) {
445	          const charLinks = validCharIds.map((cid) => ({ asset_id: assetId, character_id: cid }));
446	          await client.from("asset_characters").upsert(charLinks, { onConflict: "asset_id,character_id" });
447	        }
448	      }
449	
450	      // Upsert files_used entries to sku_files_used (licensed products only)
451	      if (Array.isArray(tagData.files_used) && (tagData.files_used as string[]).length > 0 && asset.sku) {
452	        const rows = (tagData.files_used as string[])
453	          .filter((f) => typeof f === "string" && f.trim().length > 0)
454	          .map((f) => ({ sku: asset.sku as string, file_name: f.trim() }));
455	        if (rows.length > 0) {
456	          await client.from("sku_files_used").upsert(rows, { onConflict: "sku,file_name" });
457	        }
458	      }
