1	/**
2	 * OpenRouter client — unified AI gateway for all model calls.
3	 *
4	 * Uses the OpenAI-compatible chat completions API.
5	 * Replaces direct calls to Google Gemini and Anthropic APIs.
6	 *
7	 * All models are specified as OpenRouter model IDs, e.g.:
8	 *   "google/gemini-2.0-flash-001"
9	 *   "anthropic/claude-3.5-haiku"
10	 */
11	
12	import { logger } from "./logger.js";
13	
14	const OPENROUTER_URL = "https://openrouter.ai/api/v1/chat/completions";
15	const DEFAULT_TIMEOUT_MS = 60_000;
16	const MAX_RETRIES = 2;
17	
18	export class OpenRouterError extends Error {
19	  constructor(public status: number, public body: string) {
20	    super(`OpenRouter ${status}: ${body.slice(0, 300)}`);
21	    this.name = "OpenRouterError";
22	  }
23	}
24	
25	// ── Types ────────────────────────────────────────────────────────────────────
26	
27	export type ContentPart =
28	  | { type: "text"; text: string }
29	  | { type: "image_url"; image_url: { url: string } };
30	
31	export interface ChatMessage {
32	  role: "system" | "user" | "assistant";
33	  content: string | ContentPart[];
34	}
35	
36	export interface ToolFunction {
37	  name: string;
38	  description?: string;
39	  parameters: Record<string, unknown>;
40	}
41	
42	export interface Tool {
43	  type: "function";
44	  function: ToolFunction;
45	}
46	
47	export interface ChatCompletionRequest {
48	  model: string;
49	  messages: ChatMessage[];
50	  tools?: Tool[];
51	  tool_choice?: { type: "function"; function: { name: string } } | "required" | "auto";
52	  max_tokens?: number;
53	  temperature?: number;
54	}
55	
56	export interface ToolCallResult {
57	  name: string;
58	  arguments: Record<string, unknown>;
59	}
60	
61	export interface ChatCompletionResult {
62	  toolCalls?: ToolCallResult[];
63	  content?: string;
64	}
65	
66	// ── Helpers ──────────────────────────────────────────────────────────────────
67	
68	/** Build an image content part from a base64-encoded image */
69	export function imageContent(base64: string, mimeType: string): ContentPart {
70	  return {
71	    type: "image_url",
72	    image_url: { url: `data:${mimeType};base64,${base64}` },
73	  };
74	}
75	
76	/** Build a tool definition from name, description, and JSON Schema parameters */
77	export function tool(name: string, description: string, parameters: Record<string, unknown>): Tool {
78	  return {
79	    type: "function",
80	    function: { name, description, parameters },
81	  };
82	}
83	
84	// ── Main call ────────────────────────────────────────────────────────────────
85	
86	export async function chatCompletion(
87	  apiKey: string,
88	  request: ChatCompletionRequest,
89	  timeoutMs: number = DEFAULT_TIMEOUT_MS,
90	): Promise<ChatCompletionResult> {
91	  // Some models don't support the specific-function or "required" tool_choice forms.
92	  // Fall back through the compatibility ladder automatically on a 404.
93	  const toolChoiceFallbacks: Array<ChatCompletionRequest["tool_choice"]> = [];
94	  if (request.tool_choice && request.tool_choice !== "auto") {
95	    if (request.tool_choice !== "required") toolChoiceFallbacks.push("required");
96	    toolChoiceFallbacks.push("auto");
97	  }
98	
99	  let currentRequest = request;
100	  let lastError: Error | null = null;
101	
102	  for (let attempt = 0; attempt <= MAX_RETRIES; attempt++) {
103	    let response: Response;
104	    try {
105	      response = await fetch(OPENROUTER_URL, {
106	        method: "POST",
107	        headers: {
108	          "Authorization": `Bearer ${apiKey}`,
109	          "Content-Type": "application/json",
110	          "HTTP-Referer": "https://popdam.com",
111	          "X-Title": "popdam3",
112	        },
113	        signal: AbortSignal.timeout(timeoutMs),
114	        body: JSON.stringify(currentRequest),
115	      });
116	    } catch (e) {
117	      lastError = e instanceof Error ? e : new Error(String(e));
118	      if (attempt < MAX_RETRIES) {
119	        await new Promise((r) => setTimeout(r, 2000 * (attempt + 1)));
120	        continue;
121	      }
122	      throw lastError;
123	    }
124	
125	    if (response.ok) {
126	      const data = await response.json() as {
127	        choices?: Array<{
128	          message?: {
129	            content?: string;
130	            tool_calls?: Array<{
131	              function: { name: string; arguments: string };
132	            }>;
133	          };
134	        }>;
135	      };
136	
137	      const choice = data.choices?.[0]?.message;
138	      if (!choice) {
139	        throw new Error("OpenRouter returned no choices");
140	      }
141	
142	      if (choice.tool_calls && choice.tool_calls.length > 0) {
143	        return {
144	          toolCalls: choice.tool_calls.map((tc) => ({
145	            name: tc.function.name,
146	            arguments: JSON.parse(tc.function.arguments),
147	          })),
148	        };
149	      }
150	
151	      return { content: choice.content || "" };
152	    }
153	
154	    if (response.status === 429) {
155	      // Rate limited — wait and retry
156	      const retryAfter = parseInt(response.headers.get("retry-after") || "5", 10);
157	      logger.warn("openrouter: rate limited", { attempt, retryAfter });
158	      if (attempt < MAX_RETRIES) {
159	        await new Promise((r) => setTimeout(r, retryAfter * 1000));
160	        continue;
161	      }
162	      throw new OpenRouterError(429, "Rate limited after retries");
163	    }
164	
165	    if (response.status >= 500 && attempt < MAX_RETRIES) {
166	      logger.warn("openrouter: transient error, retrying", { status: response.status, attempt });
167	      await new Promise((r) => setTimeout(r, 2000 * (attempt + 1)));
168	      continue;
169	    }
170	
171	    const errBody = await response.text();
172	
173	    // tool_choice compatibility fallback: if the model rejects our tool_choice
174	    // value, retry with the next less-strict value in the ladder.
175	    if (response.status === 404 && errBody.includes("tool_choice") && toolChoiceFallbacks.length > 0) {
176	      const nextChoice = toolChoiceFallbacks.shift()!;
177	      logger.warn("openrouter: tool_choice not supported, retrying with fallback", {
178	        model: currentRequest.model,
179	        from: currentRequest.tool_choice,
180	        to: nextChoice,
181	      });
182	      currentRequest = { ...currentRequest, tool_choice: nextChoice };
183	      attempt--; // don't count this against retry budget
184	      continue;
185	    }
186	
187	    throw new OpenRouterError(response.status, errBody);
188	  }
189	
190	  throw lastError ?? new Error("OpenRouter request failed after retries");
191	}
