1	/**
2	 * SeaDrive installer mirror.
3	 *
4	 * Periodically (weekly) scrapes the official Seafile download page for the latest
5	 * SeaDrive (virtual-drive) client version, and — if it's newer than what we've
6	 * mirrored — downloads the macOS .pkg and Windows .msi and uploads them to our
7	 * DigitalOcean Spaces bucket. The pinned result is written to
8	 * admin_config.SEADRIVE_LATEST, which the PopDAM Downloads page reads so it only
9	 * ever offers the latest version, hosted by us.
10	 *
11	 * Spaces credentials are read from admin_config (DO_SPACES_*) — same source the
12	 * bridge agent uses — so no extra worker env vars are required.
13	 */
14	
15	import { S3Client, PutObjectCommand } from "@aws-sdk/client-s3";
16	import { db } from "../supabase.js";
17	import { logger } from "../logger.js";
18	
19	const STORE_KEY = "SEADRIVE_LATEST";
20	const DOWNLOAD_PAGE = "https://www.seafile.com/en/download/";
21	const CHECK_INTERVAL_MS = 7 * 24 * 60 * 60 * 1000; // weekly
22	const SPACES_PREFIX = "seadrive";
23	
24	interface SeaDriveLatest {
25	  version: string;
26	  mac_url: string | null;
27	  win_url: string | null;
28	  source: { mac: string | null; win: string | null };
29	  mirrored: boolean;
30	  checked_at: string;
31	}
32	
33	interface SpacesCfg {
34	  key: string;
35	  secret: string;
36	  region: string;
37	  bucket: string;
38	  baseUrl: string;
39	}
40	
41	async function readConfig<T = unknown>(keys: string[]): Promise<Record<string, T>> {
42	  const { data } = await db().from("admin_config").select("key, value").in("key", keys);
43	  const out: Record<string, T> = {};
44	  for (const row of data ?? []) out[row.key as string] = row.value as T;
45	  return out;
46	}
47	
48	async function loadSpacesCfg(): Promise<SpacesCfg | null> {
49	  const c = await readConfig<string>([
50	    "DO_SPACES_KEY", "DO_SPACES_SECRET", "DO_SPACES_REGION", "DO_SPACES_BUCKET", "DO_SPACES_BASE_URL",
51	  ]);
52	  if (!c.DO_SPACES_KEY || !c.DO_SPACES_SECRET || !c.DO_SPACES_BUCKET) return null;
53	  return {
54	    key: c.DO_SPACES_KEY,
55	    secret: c.DO_SPACES_SECRET,
56	    region: c.DO_SPACES_REGION || "nyc3",
57	    bucket: c.DO_SPACES_BUCKET,
58	    baseUrl: (c.DO_SPACES_BASE_URL || `https://${c.DO_SPACES_BUCKET}.${c.DO_SPACES_REGION}.digitaloceanspaces.com`).replace(/\/$/, ""),
59	  };
60	}
61	
62	/** Parse the download page for the newest SeaDrive version + installer URLs. */
63	function parseDownloadPage(html: string): { version: string; mac: string | null; win: string | null } | null {
64	  const urls = Array.from(
65	    html.matchAll(/https?:\/\/[^\s"'<>]*\/seadrive-(\d+\.\d+\.\d+)[^\s"'<>]*\.(pkg|msi)/gi),
66	  ).map((m) => ({ url: m[0], version: m[1], ext: m[2].toLowerCase() }));
67	  if (urls.length === 0) return null;
68	
69	  // Highest semver wins.
70	  const cmp = (a: string, b: string) => {
71	    const pa = a.split(".").map(Number), pb = b.split(".").map(Number);
72	    for (let i = 0; i < 3; i++) if (pa[i] !== pb[i]) return pa[i] - pb[i];
73	    return 0;
74	  };
75	  const version = urls.map((u) => u.version).sort(cmp).at(-1)!;
76	  const forVersion = urls.filter((u) => u.version === version);
77	  return {
78	    version,
79	    mac: forVersion.find((u) => u.ext === "pkg")?.url ?? null,
80	    win: forVersion.find((u) => u.ext === "msi")?.url ?? null,
81	  };
82	}
83	
84	async function mirrorOne(
85	  s3: S3Client,
86	  cfg: SpacesCfg,
87	  sourceUrl: string,
88	  ext: string,
89	  version: string,
90	): Promise<string> {
91	  const res = await fetch(sourceUrl);
92	  if (!res.ok) throw new Error(`download ${sourceUrl} failed (${res.status})`);
93	  const body = Buffer.from(await res.arrayBuffer());
94	  const objectKey = `${SPACES_PREFIX}/seadrive-${version}.${ext}`;
95	  await s3.send(
96	    new PutObjectCommand({
97	      Bucket: cfg.bucket,
98	      Key: objectKey,
99	      Body: body,
100	      ACL: "public-read",
101	      ContentType: ext === "pkg" ? "application/octet-stream" : "application/x-msi",
102	    }),
103	  );
104	  logger.info("seadrive-mirror: uploaded", { objectKey, bytes: body.length });
105	  return `${cfg.baseUrl}/${objectKey}`;
106	}
107	
108	/**
109	 * Run at most weekly. Returns silently on any error — this is best-effort and
110	 * must never disrupt the bulk-operation loop.
111	 */
112	export async function maybeMirrorSeaDrive(): Promise<void> {
113	  try {
114	    const existingMap = await readConfig<SeaDriveLatest>([STORE_KEY]);
115	    const existing = existingMap[STORE_KEY];
116	    if (existing?.checked_at) {
117	      const age = Date.now() - new Date(existing.checked_at).getTime();
118	      if (age >= 0 && age < CHECK_INTERVAL_MS) return; // throttled
119	    }
120	
121	    const pageRes = await fetch(DOWNLOAD_PAGE);
122	    if (!pageRes.ok) {
123	      logger.warn("seadrive-mirror: download page fetch failed", { status: pageRes.status });
124	      return;
125	    }
126	    const parsed = parseDownloadPage(await pageRes.text());
127	    if (!parsed) {
128	      logger.warn("seadrive-mirror: could not parse a SeaDrive version from the page");
129	      return;
130	    }
131	
132	    const now = new Date().toISOString();
133	    const alreadyCurrent = existing?.version === parsed.version && existing?.mirrored;
134	    if (alreadyCurrent) {
135	      // Same version already mirrored — just bump checked_at.
136	      await db().from("admin_config").upsert(
137	        { key: STORE_KEY, value: { ...existing, checked_at: now }, updated_at: now },
138	        { onConflict: "key" },
139	      );
140	      return;
141	    }
142	
143	    const cfg = await loadSpacesCfg();
144	    let macUrl: string | null = parsed.mac;
145	    let winUrl: string | null = parsed.win;
146	    let mirrored = false;
147	
148	    if (cfg) {
149	      const s3 = new S3Client({
150	        region: cfg.region,
151	        endpoint: `https://${cfg.region}.digitaloceanspaces.com`,
152	        credentials: { accessKeyId: cfg.key, secretAccessKey: cfg.secret },
153	        forcePathStyle: false,
154	      });
155	      try {
156	        if (parsed.mac) macUrl = await mirrorOne(s3, cfg, parsed.mac, "pkg", parsed.version);
157	        if (parsed.win) winUrl = await mirrorOne(s3, cfg, parsed.win, "msi", parsed.version);
158	        mirrored = true;
159	      } catch (e) {
160	        // Fall back to the official source URLs if the mirror fails.
161	        logger.error("seadrive-mirror: upload failed; falling back to official URLs", {
162	          error: e instanceof Error ? e.message : String(e),
163	        });
164	        macUrl = parsed.mac;
165	        winUrl = parsed.win;
166	        mirrored = false;
167	      }
168	    } else {
169	      logger.warn("seadrive-mirror: Spaces config missing; recording official URLs only");
170	    }
171	
172	    const value: SeaDriveLatest = {
173	      version: parsed.version,
174	      mac_url: macUrl,
175	      win_url: winUrl,
176	      source: { mac: parsed.mac, win: parsed.win },
177	      mirrored,
178	      checked_at: now,
179	    };
180	    await db().from("admin_config").upsert(
181	      { key: STORE_KEY, value, updated_at: now },
182	      { onConflict: "key" },
183	    );
184	    logger.info("seadrive-mirror: recorded latest", { version: parsed.version, mirrored });
185	  } catch (e) {
186	    logger.error("seadrive-mirror: unexpected error", {
187	      error: e instanceof Error ? e.message : String(e),
188	    });
189	  }
190	}
