1	/**
2	 * Shared types — mirrors the OpState / OpStatus used by the frontend and edge functions.
3	 */
4	
5	export type OpStatus =
6	  | "idle"
7	  | "running"
8	  | "queued"
9	  | "completed"
10	  | "interrupted"
11	  | "failed";
12	
13	export interface OpState {
14	  status: OpStatus;
15	  cursor?: number | string;
